#!/usr/bin/env python3
"""Generate a long-path makefile for finding 009."""
from pathlib import Path
import os
import sys


def main() -> None:
    outdir = Path(sys.argv[1]) if len(sys.argv) > 1 else Path(__file__).resolve().parent
    outdir.mkdir(parents=True, exist_ok=True)
    path_max = os.pathconf(str(outdir), "PC_PATH_MAX")
    component = "A" * (path_max - 2)
    crafted = "/" + component + "/"
    makefile = outdir / "009-unchecked-separator-path.mk"

    makefile.write_text(
        "# Generated by 009-unchecked-separator-path.py\n"
        "# Two slash-terminated targets share an empty basename; alias resolution calls absolute_reduce.\n"
        f"{crafted}:\n"
        "\t@:\n"
        f"{component}/:\n"
        "\t@:\n",
        encoding="ascii",
    )
    print(f"wrote {makefile}")
    print(f"PATH_MAX used: {path_max}")
    print(f"run: make -f {makefile} {component}/")


if __name__ == "__main__":
    main()
